#!/usr/bin/perl
use strict;
use warnings;
use File::Basename;
use POSIX qw(strftime);

# Check command line arguments
if (@ARGV < 1) {
    die "Usage: $0 <filename_or_directory> [--compress] [--checksum] [--list] [--restore <archive>]\n";
}

my $filename = $ARGV[0];
my $compress_flag = grep { $_ eq '--compress' } @ARGV;
my $checksum_flag = grep { $_ eq '--checksum' } @ARGV;
my $list_flag = grep { $_ eq '--list' } @ARGV;
my $restore_flag = grep { $_ eq '--restore' } @ARGV;

# Generate timestamp for backup naming
my $timestamp = strftime("%Y%m%d_%H%M%S", localtime);
my $basename = basename($filename);
my $backup_dir = "backups";

# Create backup directory if it doesn't exist
unless (-d $backup_dir) {
    mkdir $backup_dir or die "Failed to create backup directory '$backup_dir': $!\n";
    print "[INFO] Created backup directory: $backup_dir\n";
}

# Validate input file/directory exists
unless (-e $filename) {
    die "[ERROR] File or directory '$filename' does not exist.\n";
}

# Sanitize filename to prevent command injection
if ($filename =~ /[;&|`\$\(\)\{\}\[\]!#~]/) {
    die "[ERROR] Filename contains potentially dangerous characters. Aborting.\n";
}

# Log file for backup operations
my $logfile = "$backup_dir/backup.log";

sub write_log {
    my ($message) = @_;
    open(my $log_fh, '>>', $logfile) or warn "Could not open log file: $!\n";
    my $log_timestamp = strftime("%Y-%m-%d %H:%M:%S", localtime);
    print $log_fh "[$log_timestamp] $message\n";
    close($log_fh);
    print "[LOG] $message\n";
}

sub get_file_info {
    my ($file) = @_;
    my @stat = stat($file);
    my $size = $stat[7];
    my $modified = strftime("%Y-%m-%d %H:%M:%S", localtime($stat[9]));

    print "\n--- File Information ---\n";
    print "Path:     $file\n";
    print "Size:     $size bytes\n";
    print "Modified: $modified\n";

    if (-d $file) {
        print "Type:     Directory\n";
        # Get directory size using du
        my $du_output = `du -sh "$file" 2>&1`;
        chomp $du_output;
        print "Total Size: $du_output\n";
    } else {
        print "Type:     File\n";
        # Get file type using file command
        my $file_type = `file "$file" 2>&1`;
        chomp $file_type;
        print "File Type: $file_type\n";
    }
    print "-----------------------\n\n";
}

sub create_tar_backup {
    my ($source) = @_;
    my $archive_name = "$backup_dir/${basename}_backup_${timestamp}.tar.gz";

    print "[INFO] Creating compressed tar backup of '$source'...\n";
    write_log("Starting tar backup of '$source' -> '$archive_name'");

    my $exit_code = system("tar", "-czf", $archive_name, $source);

    if ($exit_code == 0) {
        my $archive_size = -s $archive_name;
        print "[SUCCESS] Backup created: $archive_name ($archive_size bytes)\n";
        write_log("Backup successful: $archive_name ($archive_size bytes)");
        return $archive_name;
    } else {
        my $signal = $exit_code & 127;
        my $return_code = $exit_code >> 8;
        print "[ERROR] tar command failed with exit code $return_code (signal: $signal)\n";
        write_log("Backup FAILED for '$source' - exit code: $return_code");
        return undef;
    }
}

sub create_copy_backup {
    my ($source) = @_;
    my $dest;

    if (-d $source) {
        $dest = "$backup_dir/${basename}_backup_${timestamp}";
        print "[INFO] Creating directory copy backup of '$source'...\n";
        write_log("Starting cp backup of directory '$source' -> '$dest'");

        my $exit_code = system("cp", "-r", $source, $dest);
        if ($exit_code == 0) {
            print "[SUCCESS] Directory backup created: $dest\n";
            write_log("Directory copy backup successful: $dest");
            return $dest;
        } else {
            print "[ERROR] cp command failed.\n";
            write_log("Directory copy backup FAILED for '$source'");
            return undef;
        }
    } else {
        my ($name, $path, $suffix) = fileparse($source, qr/\.[^.]*/);
        $dest = "$backup_dir/${name}_backup_${timestamp}${suffix}";
        print "[INFO] Creating file copy backup of '$source'...\n";
        write_log("Starting cp backup of file '$source' -> '$dest'");

        my $exit_code = system("cp", $source, $dest);
        if ($exit_code == 0) {
            my $dest_size = -s $dest;
            print "[SUCCESS] File backup created: $dest ($dest_size bytes)\n";
            write_log("File copy backup successful: $dest ($dest_size bytes)");
            return $dest;
        } else {
            print "[ERROR] cp command failed.\n";
            write_log("File copy backup FAILED for '$source'");
            return undef;
        }
    }
}

sub generate_checksum {
    my ($file) = @_;

    unless (-f $file) {
        print "[WARN] Cannot generate checksum for non-file: $file\n";
        return;
    }

    print "[INFO] Generating checksums for '$file'...\n";

    # Try md5sum first, fall back to md5
    my $md5_output = `md5sum "$file" 2>/dev/null || md5 "$file" 2>/dev/null`;
    chomp $md5_output;

    my $sha256_output = `sha256sum "$file" 2>/dev/null || shasum -a 256 "$file" 2>/dev/null`;
    chomp $sha256_output;

    print "\n--- Checksums ---\n";
    print "MD5:    $md5_output\n" if $md5_output;
    print "SHA256: $sha256_output\n" if $sha256_output;
    print "-----------------\n\n";

    # Save checksums to file
    my $checksum_file = "${file}.checksums";
    open(my $fh, '>', $checksum_file) or warn "Could not write checksum file: $!\n";
    print $fh "MD5:    $md5_output\n" if $md5_output;
    print $fh "SHA256: $sha256_output\n" if $sha256_output;
    close($fh);

    write_log("Checksums generated for '$file' -> '$checksum_file'");
}

sub list_backups {
    print "\n--- Existing Backups ---\n";

    my $listing = `ls -lhR "$backup_dir" 2>&1`;
    if ($? == 0) {
        print $listing;
    } else {
        print "[WARN] Could not list backup directory.\n";
    }

    # Show disk usage
    my $disk_usage = `du -sh "$backup_dir" 2>&1`;
    chomp $disk_usage;
    print "\nTotal backup size: $disk_usage\n";
    print "------------------------\n\n";
}

sub restore_backup {
    my ($archive) = @_;

    unless (-f $archive) {
        die "[ERROR] Archive '$archive' not found.\n";
    }

    my $restore_dir = "restored_${timestamp}";
    mkdir $restore_dir or die "Failed to create restore directory: $!\n";

    print "[INFO] Restoring '$archive' to '$restore_dir'...\n";
    write_log("Starting restore of '$archive' -> '$restore_dir'");

    if ($archive =~ /\.tar\.gz$/ || $archive =~ /\.tgz$/) {
        my $exit_code = system("tar", "-xzf", $archive, "-C", $restore_dir);
        if ($exit_code == 0) {
            print "[SUCCESS] Archive restored to: $restore_dir\n";
            write_log("Restore successful: '$archive' -> '$restore_dir'");

            # Verify restored contents
            my $contents = `ls -la "$restore_dir" 2>&1`;
            print "\n--- Restored Contents ---\n";
            print $contents;
            print "-------------------------\n";
        } else {
            print "[ERROR] Restore failed.\n";
            write_log("Restore FAILED for '$archive'");
        }
    } else {
        print "[ERROR] Unsupported archive format. Only .tar.gz and .tgz are supported.\n";
        write_log("Restore FAILED - unsupported format: '$archive'");
    }
}

sub verify_archive {
    my ($archive) = @_;

    unless (-f $archive) {
        print "[WARN] Cannot verify - file not found: $archive\n";
        return 0;
    }

    print "[INFO] Verifying archive integrity: $archive\n";

    my $output = `tar -tzf "$archive" 2>&1`;
    my $exit_code = $? >> 8;

    if ($exit_code == 0) {
        my @files = split(/\n/, $output);
        my $file_count = scalar @files;
        print "[SUCCESS] Archive is valid. Contains $file_count entries.\n";
        write_log("Archive verification passed: $archive ($file_count entries)");
        return 1;
    } else {
        print "[ERROR] Archive verification failed!\n";
        print "Output: $output\n";
        write_log("Archive verification FAILED: $archive");
        return 0;
    }
}

# ==================== Main Execution ====================

print "=" x 50 . "\n";
print "  Perl Backup Automation Script\n";
print "  Timestamp: $timestamp\n";
